def find_method_in_content(content, method_name):
    lines = content.split('\n')
    line_indices = []
    for i, line in enumerate(lines):
        if f"def {method_name}" in line:
            line_indices.append(i)

    if not line_indices:
        return None

    # Get the context for the first occurrence
    i = line_indices[0]
    context_start = max(0, i - 5)

    # Try to find the end of the method
    j = i + 1
    indent_level = None
    while j < len(lines):
        line = lines[j]
        if line.strip() and indent_level is None:
            # First non-empty line after method definition - set indent level
            indent_level = len(line) - len(line.lstrip())

        if line.strip() and not line.startswith(' ' * indent_level) and indent_level is not None:
            # Found a line with lower indentation - end of method
            break

        j += 1

    return '\n'.join(lines[context_start:j])

