import re

def search_in_content(content, search_term, context_lines=2, max_results=5):
    pattern = re.compile(f"File: (.*?)\n={{{2,}}}\n(.*?{search_term}.*?)(?=\n={{{2,}}}\nFile:|\Z)", 
                        re.DOTALL | re.IGNORECASE)

    results = []
    for match in pattern.finditer(content):
        filename = match.group(1).strip()
        content_snippet = match.group(2)

        # Extract lines around the search term
        lines = content_snippet.split('\n')
        matching_lines = []
        for i, line in enumerate(lines):
            if search_term.lower() in line.lower():
                start = max(0, i - context_lines)
                end = min(len(lines), i + context_lines + 1)
                matching_lines.append((i, lines[start:end]))

        for line_num, line_context in matching_lines[:max_results]:
            results.append({
                'filename': filename,
                'line_number': line_num,
                'context': '\n'.join(line_context)
            })

        if len(results) >= max_results:
            break

    return results

