def print_dir_structure(tree, prefix="", is_last=True, depth=0, max_depth=3):
    if depth > max_depth:
        return

    name = tree.get("name", "")
    if not name:
        # This is the root
        for i, child in enumerate(tree.get("children", [])):
            is_last_child = i == len(tree.get("children", [])) - 1
            print_dir_structure(child, "", is_last_child, depth + 1, max_depth)
    else:
        connector = "└── " if is_last else "├── "
        print(f"{prefix}{connector}{name}")

        new_prefix = prefix + ("    " if is_last else "│   ")
        children = tree.get("children", [])
        for i, child in enumerate(children):
            is_last_child = i == len(children) - 1
            print_dir_structure(child, new_prefix, is_last_child, depth + 1, max_depth)

